String text = "Hello";
System.out.println(text.charAt(0)); // H
System.out.println(text.charAt(4)); // o

String text = "Hello World";
System.out.println(text.substring(0, 5)); // Hello
System.out.println(text.substring(6));    // World

String a = "Hello";
String b = "hello";

System.out.println(a.equals(b));           // false -- case matters
System.out.println(a.equalsIgnoreCase(b)); // true

String csv = "apple,banana,cherry";
String[] fruits = csv.split(",");

for (String fruit : fruits) {
    System.out.println(fruit);
}

public class Main {
    public static void main(String[] args) {
        String email = "  Aman.Raj@Example.com  ";

        String cleaned = email.trim().toLowerCase();
        System.out.println(cleaned);

        int atIndex = cleaned.indexOf("@");
        String username = cleaned.substring(0, atIndex);
        System.out.println("Username: " + username);
    }
}

